return [{ json: {
  success: false, error_code: 'DB_INSERT_FAILED',
  error_message: 'Database insert failed. GCal event rolled back.',
  data: null,
  _meta: { source: 'WF2_Booking_Orchestrator', timestamp: new Date().toISOString(), workflow_id: $workflow.id || 'unknown' }
}}];

const db = $('Create DB Booking').first().json;
const gcal = $('Extract GCal Event ID').first().json;
const v = $('Validate Input').first().json;

return [{ json: {
  success: true, error_code: null, error_message: null,
  data: {
    booking_id: db.booking_id,
    gcal_event_id: gcal.gcal_event_id,
    idempotency_key: v.idempotency_key,
    provider_id: v.provider_id,
    service_id: v.service_id,
    start_time: v.start_time,
    end_time: v.end_time,
    status: 'confirmed',
    is_duplicate: false
  },
  _meta: { source: 'WF2_Booking_Orchestrator', timestamp: new Date().toISOString(), workflow_id: $workflow.id || 'unknown' }
}}];

const input = $input.first().json;
if (input.message) {
   return [{ json: { db_success: false } }];
}
return [{ json: { db_success: true } }];
